FROM skillrace/fix-failing-test:base
# >>> SKILLRACE TAIL >>>
RUN apt-get update && apt-get install -y python3-pip
RUN pip install --break-system-packages pytest
RUN cat > /workspace/mathlib.py <<'EOF'
def factorial(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    result = 1
    for i in range(1, n + 1):
        result *= i
    return result


def fib(n):
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a


class InvalidDivisionError(ValueError):
    pass


def division(a, b):
    if b == 0:
        raise InvalidDivisionError("Cannot divide by zero")
    return a / b
EOF
RUN cat > /workspace/test_mathlib.py <<'EOF'
import pytest
from mathlib import factorial, fib, division, InvalidDivisionError


def test_factorial_base_cases():
    assert factorial(0) == 1
    assert factorial(1) == 1


def test_factorial_five():
    assert factorial(5) == 120


def test_fib():
    assert fib(7) == 13


def test_division_by_zero():
    with pytest.raises(InvalidDivisionError):
        division(10, 0)
EOF
RUN cd /workspace && git add -A && git commit -q -m "skillrace: test setup" || true
